#include <iostream> // Required for std::cin, std::cout
#include <iomanip>  // Required for std::fixed, std::showpoint, std::setprecision

int main()
{
  int numStudents;    // Number of students
  int numTests;       // Number of tests per student
  double total;       // Accumulator for total scores
  double average;     // Average test score

  // Set up numeric output formatting to display floating-point numbers
  // in fixed-point notation with the decimal point always shown and 1 decimal place.
  std::cout << std::fixed << std::showpoint << std::setprecision(1);

  // Get the number of students from user input.
  std::cout << "This program averages test scores.\n";
  std::cout << "For how many students do you have scores? ";
  std::cin >> numStudents;

  // Get the number of test scores per student from user input.
  std::cout << "How many test scores does each student have? ";
  std::cin >> numTests;

  // Outer loop: Determine each student's average score.
  for (int student = 1; student <= numStudents; student++)
  {
    total = 0; // Initialize the accumulator for the current student.
    // Inner loop: Get scores for the current student.
    for (int test = 1; test <= numTests; test++)
    {
      double score;
      std::cout << "Enter score " << test << " for ";
      std::cout << "student " << student << ": ";
      std::cin >> score;
      total += score; // Add current score to the total.
    }
    average = total / numTests; // Calculate average for the current student.
    std::cout << "The average score for student " << student;
    std::cout << " is " << average << ".\n\n"; // Display the average.
  }
  return 0;
}

