#include <iostream> // For console input/output
#include <fstream>  // For file stream operations
#include <string>   // For using string data type

int main()
{
    // 1. Declare variables to hold user input
    std::string name;
    int age;
    std::string city;

    // 2. Declare an ofstream object for writing to a file
    std::ofstream outputFile;

    // 3. Open the file 'user_info.txt' for output
    outputFile.open("user_info.txt");

    // 4. Check if the file opened successfully
    if (!outputFile)
    {
        std::cerr << "Error: Could not open file user_info.txt" << std::endl;
        return 1; // Indicate an error
    }

    // 5. Prompt user for input and read data
    std::cout << "Enter your name: ";
    std::getline(std::cin, name); // Use getline for names with spaces

    std::cout << "Enter your age: ";
    std::cin >> age;
    std::cin.ignore(); // Consume the leftover newline character after reading int

    std::cout << "Enter your city: ";
    std::getline(std::cin, city);

    // 6. Write the collected data to the file, each on a new line
    outputFile << "Name: " << name << std::endl;
