    if (!inputFile.is_open()) {
        std::cerr << "Error: Could not open names.txt" << std::endl;
        return 1; // Indicate an error by returning a non-zero value
    }

    std::cout << "Reading names from names.txt:" << std::endl;

    // 4. Read the first name from the file.
    //    The '>>' operator extracts data from the file stream into the 'name' variable.
    //    It reads until whitespace (space, tab, newline) is encountered.
    inputFile >> name;
