    std::cout << name << std::endl;

    // 6. Read the second name from the file.
    inputFile >> name;
    // 7. Display the second name.
    std::cout << name << std::endl;

    // 8. Read the third name from the file.
    inputFile >> name;
    // 9. Display the third name.
    std::cout << name << std::endl;

