FUNCTION ReadNextItemFromFile(file_stream, target_variable)
    // Precondition: file_stream is open and at a valid read position.
    // Postcondition: target_variable holds the next item, and file_stream's read position
    //                is advanced past the item and its delimiter.

    DECLARE temporary_buffer AS STRING = ""
    DECLARE char AS CHARACTER

    // Read characters until a whitespace delimiter or end of file
    WHILE NOT EndOfFile(file_stream) AND NOT IsWhitespace(PeekChar(file_stream))
        char = ReadChar(file_stream)
        APPEND char TO temporary_buffer
    END WHILE

    // Assign extracted data to the target variable
    IF LENGTH(temporary_buffer) > 0 THEN
        // Attempt automatic type conversion if target_variable is numeric
        ASSIGN temporary_buffer TO target_variable
    END IF

    // Consume the delimiter (if any)
    IF NOT EndOfFile(file_stream) AND IsWhitespace(PeekChar(file_stream)) THEN
        // Read and discard the whitespace character
        ReadChar(file_stream)
    END IF

    RETURN TRUE // Or FALSE if no data was read (e.g., at EOF initially)
END FUNCTION

